 18	import { DescriptionList, GridItem } from '@patternfly/react-core';
 19	
 20	import Affinity from './Affinity';
 21	
 22	type SchedulingSectionLeftGridProps = {
 23	  canUpdateVM: boolean;
 24	  nodes: IoK8sApiCoreV1Node[];
 25	  nodesLoaded: boolean;
 26	  onUpdateVM?: (updatedVM: V1VirtualMachine) => Promise<V1VirtualMachine>;
 27	  vm: V1VirtualMachine;
 28	  vmi?: V1VirtualMachineInstance;
 29	};
 30	
 31	const SchedulingSectionLeftGrid: FC<SchedulingSectionLeftGridProps> = ({
 32	  canUpdateVM,
 33	  nodes,
 34	  nodesLoaded,
 35	  onUpdateVM,
 36	  vm,
 37	  vmi,
 38	}) => {
 39	  const { t } = useKubevirtTranslation();
 40	  const { createModal } = useModal();
 41	
 42	  const onSubmit = useCallback(
 43	    (updatedVM: V1VirtualMachine) =>
 44	      onUpdateVM
 45	        ? onUpdateVM(updatedVM)
 46	        : k8sUpdate({
 47	            data: updatedVM,
 48	            model: VirtualMachineModel,
 49	            name: updatedVM?.metadata?.name,
 50	            ns: updatedVM?.metadata?.namespace,
 51	          }),
 52	    [onUpdateVM],
 53	  );
 54	
 55	  return (
 56	    <GridItem span={5}>
 57	      <DescriptionList className="pf-v6-c-description-list">
 58	        <VirtualMachineDescriptionItem
 59	          descriptionData={
 60	            <NodeSelectorDetailItem nodeSelector={vm?.spec?.template?.spec?.nodeSelector} />
 61	          }
 62	          onEditClick={() =>
 63	            createModal(({ isOpen, onClose }) => (
 64	              <NodeSelectorModal
 65	                isOpen={isOpen}
 66	                nodes={nodes}
 67	                nodesLoaded={nodesLoaded}
 68	                onClose={onClose}
 69	                onSubmit={onSubmit}
 70	                vm={vm}
 71	              />
 72	            ))
 73	          }
 74	          data-test-id="node-selector"
 75	          descriptionHeader={<SearchItem id="node-selector">{t('Node selector')}</SearchItem>}
 76	          isEdit={canUpdateVM}
 77	        />
 78	        <VirtualMachineDescriptionItem
 79	          onEditClick={() =>
 80	            createModal(({ isOpen, onClose }) => (
 81	              <TolerationsModal
 82	                isOpen={isOpen}
 83	                nodes={nodes}
 84	                nodesLoaded={nodesLoaded}
 85	                onClose={onClose}
 86	                onSubmit={onSubmit}
 87	                vm={vm}
 88	                vmi={vmi}
 89	              />
 90	            ))
 91	          }
 92	          data-test-id="tolerations"
 93	          descriptionData={<Tolerations vm={vm} />}
 94	          descriptionHeader={<SearchItem id="tolerations">{t('Tolerations')}</SearchItem>}
 95	          isEdit={canUpdateVM}
 96	        />
 97	        <VirtualMachineDescriptionItem
 98	          onEditClick={() =>
 99	            createModal(({ isOpen, onClose }) => (
100	              <AffinityModal
101	                isOpen={isOpen}
102	                nodes={nodes}
103	                nodesLoaded={nodesLoaded}
104	                onClose={onClose}
105	                onSubmit={onSubmit}
106	                vm={vm}
107	              />
108	            ))
109	          }
110	          data-test-id="affinity-rules"
111	          descriptionData={<Affinity vm={vm} />}
112	          descriptionHeader={<SearchItem id="affinity">{t('Affinity rules')}</SearchItem>}
113	          isEdit={canUpdateVM}
114	        />
115	        <VirtualMachineDescriptionItem
116	          bodyContent={<DeschedulerPopover />}
117	          data-test-id="descheduler"
118	          descriptionData={<Descheduler vm={vm} />}
119	          descriptionHeader={<SearchItem id="descheduler">{t('Descheduler')}</SearchItem>}
120	          isPopover
121	        />
122	      </DescriptionList>
123	    </GridItem>
124	  );
125	};
126	
127	export default SchedulingSectionLeftGrid;

